texttool_globals_dialog_2_buttons___internal_settings_jump_to_assistant_app__jump__button_text = TextObject(bs_BA="Na Audi assistant", cs_CZ="Pro Audi assistant", da_DK="Til Audi assistant", de_DE="Zum Audi assistant", el_GR="Μετάβαση στην Audi assistant", en_GB="To the Audi assistant", es_ES="Ir al Audi assistant", fi_FI="Siirry Audi assistantiin", fr_FR="Accéder à l'Audi assistant", hr_HR="Na Audi assistant", hu_HU="Az Audi assistanthez", it_IT="Vai a Audi assistant", nl_NL="Naar de Audi assistant", no_NO="Til Audi assistant", pl_PL="Przejdź do Audi assistant", pt_PT="Para Audi assistant", ro_RO="Spre Audi assistant", ru_RU="К Audi assistant", sk_SK="O Audi assistant", sl_SI="Na sistem Audi assistant", sr_RS="Na Audi assistant", sv_SE="Till Audi assistant", tr_TR="Audi assistant'a git", uk_UA="До Audi assistant")
texttool_globals_dialog_message___internal_settings__display_app_predictions_info = TextObject(bs_BA="Pretraga prikazuje aplikacije koje je sistem ocijenio kao interesantne za Vas.\nMožete uključiti i isključiti vidljivost ovih prijedloga. Aktivirajte funkciju u\nAudi assistant postavkama za mogućnost njenog korištenja.", cs_CZ="Vyhledávání zobrazuje aplikace, které systém klasifikuje jako pro vás zajímavé.\nViditelnost těchto návrhů můžete zapnout nebo vypnout.\nAbyste mohli funkci používat, aktivujte ji v nastavení Audi assistant.", da_DK="Søgningen viser dig apps, som systemet vurderer er interessante for dig.\nDu kan aktivere og deaktivere synligheden af disse forslag.\nAktiver funktionen i Audi assistant-indstillingerne for at kunne bruge den.", de_DE="Die Suche zeigt dir Apps an, die das System für dich als interessant einstuft.\nDu kannst die Sichtbarkeit dieser Vorschläge ein- und ausschalten.\nBitte aktiviere die Funktion in den Audi assistant Einstellungen, um sie nutzen\nzu können.", el_GR="Η αναζήτηση σας εμφανίζει τις εφαρμογές, τις οποίες το σύστημα αξιολογεί ως\nενδιαφέρουσες για εσάς. Μπορείτε να ενεργοποιήσετε και να απενεργοποιήσετε την\nορατότητα αυτών των προτάσεων. Ενεργοποιήστε τη λειτουργία στις ρυθμίσεις της\nAudi assistant, για να μπορέσετε να τη χρησιμοποιήσετε.", en_GB="The search shows apps that the system thinks are relevant for you. You can switch\nthe visibility of these suggestions on/off. Please activate the function in the Audi\nassistant settings to use the search.", es_ES="La búsqueda le muestra aplicaciones que el sistema considere interesantes para\nusted. Estas sugerencias se pueden mostrar y ocultar. Por favor, active la función en\nlos ajustes del Audi assistant para poder utilizarla.", fi_FI="Haussa näet sovelluksia, jotka järjestelmä luokittelee sinua mahdollisesti\nkiinnostaviksi. Voit laittaa näiden ehdotusten näkymisen päälle tai pois. Aktivoi\ntoiminto Audi assistantin asetuksista käyttääksesi sitä.", fr_FR="La recherche vous affiche des applications que le système estime intéressantes\npour vous. Vous pouvez activer et désactiver la visibilité de ces suggestions. Veuillez\nactiver la fonction dans les réglages de l'Audi assistant pour pouvoir l'utiliser.", hr_HR="Pretraživanje prikazuje aplikacije koje sustav ocijeni kao interesantne za vas. Možete\nuključiti i isključiti vidljivost tih prijedloga. Aktivirajte funkciju u postavkama Audi\nassistanta kako biste je koristili.", hu_HU="A keresés olyan alkalmazásokat mutat, amelyeket a rendszer számodra érdekesnek\nminősít. Ezeknek a javaslatoknak a láthatóságát be- és kikapcsolhatod. Ha\nhasználni szeretnéd, aktiváld a funkciót az Audi assistant beállításaiban.", it_IT="La ricerca mostra le app che il sistema ritiene interessanti per l'utente. È possibile\nattivare e disattivare la visibilità di questi suggerimenti. Attivare la funzione nelle\nimpostazioni dell'Audi assistant per poterla utilizzare.", nl_NL="De zoekfunctie laat je apps zien die het systeem interessant voor je vindt. Je kunt de\nzichtbaarheid van deze suggesties in- en uitschakelen. Activeer de functie in de\ninstellingen van Audi assistant om deze te kunnen gebruiken.", no_NO="Søket viser apper som systemet vurderer som interessante for deg. Du kan slå av og\npå visning av disse forslagene. Du må aktivere funksjonen i Audi\nassistant-innstillingene for å kunne bruke den.", pl_PL="Wyszukiwanie wyświetla aplikacje, które system sklasyfikował jako interesujące dla\nCiebie. Widoczność tych sugestii można włączać i wyłączać. Aby korzystać z tej\nfunkcji, należy ją aktywować w ustawieniach Audi assistant.", pt_PT="A pesquisa apresenta aplicações que o sistema classifica como interessantes para\nti. Podes ligar e desligar a visibilidade destas recomendações. Por favor, ativa a\nfunção nos ajustes do Audi assistant para a poderes utilizar.", ro_RO="Căutarea vă arată aplicaţii, pe care sistemul le clasifică interesante pentru\ndumneavoastră. Puteţi activa şi dezactiva vizibilitatea acestor propuneri. Activaţi\nfuncţia în setările Audi assistant, pentru a le putea utiliza.", ru_RU="Поиск показывает приложения, которые система классифицирует как\nинтересные для вас. Вы можете включить или выключить видимость этих\nпредложений. Чтобы воспользоваться этой функцией, активируйте ее в\nнастройках Audi assistant.", sk_SK="Vyhľadávanie vám zobrazí aplikácie, ktoré systém považuje za zaujímavé pre vás.\nViditeľnosť týchto návrhov môžete zapnúť alebo vypnúť.\nProsím, ak chcete túto funkciu používať, aktivujte ju v nastaveniach Audi assistant.", sl_SI="Iskanje vam prikaže aplikacije, za katere sistem meni, da so zanimive za vas.\nVidnost teh predlogov lahko vključite in izključite.\nFunkcijo za uporabo aktivirajte v nastavitvah sistema Audi assistant.", sr_RS="Pretraživanje prikazuje aplikacije za koje sistem smatra da su vam interesantne.\nVi možete da uključite i isključite vidljivost ovih predloga. Aktivirajte funkciju u\npodešavanjima za Audi assistant da biste je mogli koristiti.", sv_SE="Sökningen visar appar som systemet tror kan vara intressanta för dig. Du kan visa\neller dölja dessa förslag. Aktivera funktionen i inställningarna för Audi assistant för\natt använda den.", tr_TR="Arama, sistemin ilgini çektiğini düşündüğü uygulamaları gösterir. Bu önerilerin\ngörünürlüğünü açabilir veya kapatabilirsin. Fonksiyonu kullanabilmek için, lütfen\nAudi assistant ayarlarından fonksiyonu etkinleştir.", uk_UA="Пошук показує програми, які система класифікує як цікаві для вас. Ви можете\nвмикати та вимикати показ цих пропозицій. Щоб мати змогу користуватися цією\nфункцією, активуйте її в налаштуваннях Audi assistant.")
texttool_globals_dialog_message___internal_settings__display_history_info = TextObject(bs_BA="Posljednji odabrani pojmovi za pretragu prikazuju se u toku pretrage i mogu se\nponovo koristiti. Lista rezultata za sve posljednje korištene jezike može se\nisprazniti dodirom na „Izbriši tok pretrage”.", cs_CZ="Naposledy vybrané výrazy se zobrazí v historii vyhledávání a lze je znovu použít.\nSeznam výsledků lze vymazat pro všechny naposledy použité jazyky klepnutím\nna „Vymazat historii vyhledávání“.", da_DK="De senest valgte søgeord vises i søgningen og kan anvendes igen. Du kan\ntømme resultatlisten for alle senest anvendte sprog ved at trykke på \"Slet\nsøgning\".", de_DE="Die zuletzt ausgewählten Suchbegriffe werden im Suchverlauf angezeigt und\nkönnen erneut genutzt werden. Die Ergebnisliste kann mit Tippen auf\n„Suchverlauf löschen“ für alle zuletzt verwendeten Sprachen geleert werden.", el_GR="Οι τελευταίοι επιλεγμένοι όροι αναζήτησης εμφανίζονται στο ιστορικό\nαναζήτησης και μπορούν να χρησιμοποιηθούν ξανά. Η λίστα αποτελεσμάτων\nμπορεί να διαγραφεί για όλες τις γλώσσες που χρησιμοποιήθηκαν τελευταία,\n πιέζοντας σύντομα \"Διαγραφή ιστορικού αναζήτησης\".", en_GB="The most recently used search terms are shown in the search history and can\nbe used again. You can clear the result list for all recently used languages by\ntapping on \"Delete search history\".", es_ES="Los últimos términos de búsqueda seleccionados se muestran en el historial de\nbúsqueda y se pueden utilizar de nuevo. La lista de resultados se puede vaciar\npulsando en \"Borrar historial de búsqueda\" en todos los idiomas utilizados.", fi_FI="Viimeksi käytetyt hakusanat näkyvät hakuhistoriassa ja niitä voidaan käyttää\nuudelleen. Hakutulosten lista kaikilla viimeksi käytetyillä kielillä voidaan\ntyhjentää painamalla kohtaa \"Poista hakuhistoria\".", fr_FR="Les termes recherchés récemment sont affichés dans l'historique des\nrecherches et peuvent être réutilisés. La liste des résultats peut être effacée\npour toutes les langues récemment utilisées en appuyant brièvement sur\n«Effacer l'historique des recherches».", hr_HR="Zadnji odabrani pojmovi za traženje prikazuju se u tijeku pretraživanja i mogu se\nponovno koristiti. Popis s rezultatima može se dodirom na \"Izbrisati tijek\npretraživanja\" isprazniti za sve zadnje korištene jezike.", hu_HU="A legutóbb kiválasztott keresőszavak megjelennek a keresési előzményekben,\nés újra felhasználhatók. A találati lista az összes legutóbb használt nyelvhez\nkiüríthető a „Keresési előzmények törlése” megérintésével.", it_IT="Le ultime voci selezionate per la ricerca vengono visualizzate nella cronologia\nricerche e possono essere riutilizzate. L'elenco dei risultati può essere\ncancellato per tutte le lingue utilizzate di recente toccando \"Cancella\ncronologia ricerche\".", nl_NL="De laatst geselecteerde zoekbegrippen worden in de zoekgeschiedenis\nweergegeven en kunnen opnieuw worden gebruikt. De resultaatlijst kan voor\nalle laatst gebruikte talen worden geleegd door te tikken op \"Zoekgeschiedenis\nwissen\".", no_NO="De siste søkeordene vises i søkehistorikken og kan brukes igjen. Du kan tømme\nresultatlisten for alle de sist brukte språkene ved å trykke på «Slett\nsøkehistorikk».", pl_PL="Ostatnio wybrane terminy wyszukiwania są wyświetlane w historii wyszukiwania\ni mogą zostać użyte ponownie. Listę wyników można wyczyścić, dotykając „Usuń\nwyszukiwanie” dla wszystkich używanych ostatnio języków.", pt_PT="Os últimos tópicos de pesquisa selecionados são apresentados no decorrer da\npesquisa e podem voltar a ser utilizados. A lista de resultados pode ser\nesvaziada tocando em \"Apagar pesquisa\" para todos os últimos idiomas\nselecionados.", ro_RO="Ultimii termeni de căutare selectaţi vor fi afişaţi în istoricul căutărilor şi pot fi\nreutilizaţi. Lista cu rezultate poate fi golită pentru toate limbile utilizate\nanterior apăsând pe \"Ştergere istoric căutări\".", ru_RU="Последние выбранные ключевые слова отображаются в журнале поиска и\nмогут быть использованы снова. Список результатов можно очистить для\nвсех недавно использовавшихся языков, нажав на «Удалить журнал поиска».", sk_SK="Naposledy zvolené hľadané výrazy sa zobrazia v prehľade vyhľadávania a je\nmožné ich znova použiť. Zoznam výsledkov je možné vyprázdniť pre všetky\nnedávno použité jazyky krátkym stlačením na „Vymazať prehľad vyhľadávania“.", sl_SI="Nazadnje izbrani iskalni pojmi so prikazani v zgodovini iskanja in jih je mogoče\nponovno uporabiti. Seznam rezultatov lahko za vse nazadnje uporabljene jezike\nizbrišete s pritiskom na \"Brisanje iskanja\".", sr_RS="Poslednji izabrani pojmovi za pretraživanje prikazuju se u toku pretraživanja i\nmogu ponovo da se koriste. Lista rezultata za sve poslednje korišćene jezike\nmože da se isprazni pritiskom na „Izbriši tok pretraživanja”.", sv_SE="De senast använda sökorden visas i sökhistoriken och kan användas igen.\nResultatlistan kan tömmas genom att trycka på \"Radera sökhistorik\" för alla\nsenast använda språk.", tr_TR="En son seçilen arama terimleri, arama geçmişinde görüntülenir ve tekrar\nkullanılabilir. Sonuç listesi \"Arama geçmişini sil\" üzerine dokunarak yakın\nzamanda kullanılan tüm diller için boşaltılabilir.", uk_UA="Останні вибрані умови пошуку відображаються в історії пошуку та можуть\nбути використані знову. Список результатів можна очистити для всіх\nнещодавно використаних мов, натиснувши кнопку «Видалити історію пошуку».")
texttool_globals_dialog_message___internal_settings__jump_to_assistant_app = TextObject(bs_BA="Pretraga prikazuje aplikacije koje je sistem ocijenio kao interesantne za Vas. Možete\nuključiti i isključiti vidljivost ovih prijedloga. Aktivirajte funkciju u Audi assistant\npostavkama za mogućnost njenog korištenja.", cs_CZ="Vyhledávání zobrazuje aplikace, které systém klasifikuje jako pro vás zajímavé.\nViditelnost těchto návrhů můžete zapnout nebo vypnout. Abyste mohli funkci\npoužívat, aktivujte ji v nastavení Audi assistant.", da_DK="Søgningen viser dig apps, som systemet vurderer er interessante for dig. Du kan\naktivere og deaktivere synligheden af disse forslag. Aktiver funktionen i Audi\nassistant-indstillingerne for at kunne bruge den.", de_DE="Die Suche zeigt dir Apps an, die das System für dich als interessant einstuft.\nDu kannst die Sichtbarkeit dieser Vorschläge ein- und ausschalten. Bitte aktiviere\ndie Funktion in den Audi assistant Einstellungen, um sie nutzen zu können.", el_GR="Η αναζήτηση σας εμφανίζει τις εφαρμογές, τις οποίες το σύστημα αξιολογεί ως\nενδιαφέρουσες για εσάς. Μπορείτε να ενεργοποιήσετε και να απενεργοποιήσετε την\nορατότητα αυτών των προτάσεων. Ενεργοποιήστε τη λειτουργία στις ρυθμίσεις της\nAudi assistant, για να μπορέσετε να τη χρησιμοποιήσετε.", en_GB="The search shows apps that the system thinks are relevant for you. You can switch\nthe visibility of these suggestions on/off. Please activate the function in the Audi\nassistant settings to use the search.", es_ES="La búsqueda le muestra aplicaciones que el sistema considere interesantes para\nusted. Estas sugerencias se pueden mostrar y ocultar. Por favor, active la función en\nlos ajustes del Audi assistant para poder utilizarla.", fi_FI="Haussa näet sovelluksia, jotka järjestelmä luokittelee sinua mahdollisesti\nkiinnostaviksi. Voit laittaa näiden ehdotusten näkymisen päälle tai pois. Aktivoi\ntoiminto Audi assistantin asetuksista käyttääksesi sitä.", fr_FR="La recherche vous affiche des applications que le système estime intéressantes\npour vous. Vous pouvez activer et désactiver la visibilité de ces suggestions. Veuillez\nactiver la fonction dans les réglages de l'Audi assistant pour pouvoir l'utiliser.", hr_HR="Pretraživanje prikazuje aplikacije koje sustav ocijeni kao interesantne za vas. Možete\nuključiti i isključiti vidljivost tih prijedloga. Aktivirajte funkciju u postavkama Audi\nassistanta kako biste je koristili.", hu_HU="A keresés olyan alkalmazásokat mutat, amelyeket a rendszer számodra érdekesnek\nminősít. Ezeknek a javaslatoknak a láthatóságát be- és kikapcsolhatod. Ha\nhasználni szeretnéd, aktiváld a funkciót az Audi assistant beállításaiban.", it_IT="La ricerca mostra le app che il sistema ritiene interessanti per l'utente. È possibile\nattivare e disattivare la visibilità di questi suggerimenti. Attivare la funzione nelle\nimpostazioni dell'Audi assistant per poterla utilizzare.", nl_NL="De zoekfunctie laat je apps zien die het systeem interessant voor je vindt. Je kunt de\nzichtbaarheid van deze suggesties in- en uitschakelen. Activeer de functie in de\ninstellingen van Audi assistant om deze te kunnen gebruiken.", no_NO="Søket viser apper som systemet vurderer som interessante for deg. Du kan slå av og\npå visning av disse forslagene. Du må aktivere funksjonen i Audi\nassistant-innstillingene for å kunne bruke den.", pl_PL="Wyszukiwanie wyświetla aplikacje, które system sklasyfikował jako interesujące dla\nCiebie. Widoczność tych sugestii można włączać i wyłączać. Aby korzystać z tej\nfunkcji, należy ją aktywować w ustawieniach Audi assistant.", pt_PT="A pesquisa apresenta aplicações que o sistema classifica como interessantes para\nti. Podes ligar e desligar a visibilidade destas recomendações. Por favor, ativa a\nfunção nos ajustes do Audi assistant para a poderes utilizar.", ro_RO="Căutarea vă arată aplicaţii, pe care sistemul le clasifică interesante pentru\ndumneavoastră. Puteţi activa şi dezactiva vizibilitatea acestor propuneri. Activaţi\nfuncţia în setările Audi assistant, pentru a le putea utiliza.", ru_RU="Поиск показывает приложения, которые система классифицирует как\nинтересные для вас. Вы можете включить или выключить видимость этих\nпредложений. Чтобы воспользоваться этой функцией, активируйте ее в\nнастройках Audi assistant.", sk_SK="Vyhľadávanie vám zobrazí aplikácie, ktoré systém považuje za zaujímavé pre vás.\nViditeľnosť týchto návrhov môžete zapnúť alebo vypnúť. Prosím, ak chcete túto\nfunkciu používať, aktivujte ju v nastaveniach Audi assistant.", sl_SI="Iskanje vam prikaže aplikacije, za katere sistem meni, da so zanimive za vas. Vidnost\nteh predlogov lahko vključite in izključite. Funkcijo za uporabo aktivirajte v\nnastavitvah sistema Audi assistant.", sr_RS="Pretraživanje prikazuje aplikacije za koje sistem smatra da su vam interesantne. Vi\nmožete da uključite i isključite vidljivost ovih predloga. Aktivirajte funkciju u\npodešavanjima za Audi assistant da biste je mogli koristiti.", sv_SE="Sökningen visar appar som systemet tror kan vara intressanta för dig. Du kan visa\neller dölja dessa förslag. Aktivera funktionen i inställningarna för Audi assistant för\natt använda den.", tr_TR="Arama, sistemin ilgini çektiğini düşündüğü uygulamaları gösterir. Bu önerilerin\ngörünürlüğünü açabilir veya kapatabilirsin. Fonksiyonu kullanabilmek için, lütfen\nAudi assistant ayarlarından fonksiyonu etkinleştir.", uk_UA="Пошук показує програми, які система класифікує як цікаві для вас. Ви можете\nвмикати та вимикати показ цих пропозицій. Щоб мати змогу користуватися цією\nфункцією, активуйте її в налаштуваннях Audi assistant.")
texttool_globals_hmisdk_blockable_text___hmisdk__blockable_text_view_blocking_text = TextObject(bs_BA="Ograničeno rukovanje u toku vožnje.", cs_CZ="Omezená obsluha během jízdy.", da_DK="Begrænset betjening under kørsel.", de_DE="Eingeschränkte Bedienung während der Fahrt.", el_GR="Περιορισμένος χειρισμός κατά τη διάρκεια της οδήγησης.", en_GB="For your safety, limited operation while driving.", es_ES="Manejo limitado durante la marcha.", fi_FI="Rajoitettu käyttö ajon aikana.", fr_FR="Utilisation restreinte pendant la conduite.", hr_HR="Ograničeno rukovanje tijekom vožnje.", hu_HU="Korlátozott használat menet közben.", it_IT="Utilizzo limitato durante la marcia.", nl_NL="Beperkte bediening tijdens het rijden.", no_NO="Betjening er begrenset under kjøring.", pl_PL="Ograniczona obsługa podczas jazdy.", pt_PT="Acionamento com restrições durante a circulação.", ro_RO="Operare limitată în timpul deplasării.", ru_RU="Во время движения управление ограничено.", sk_SK="Obmedzená obsluha počas jazdy.", sl_SI="Omejeno upravljanje med vožnjo.", sr_RS="Ograničeno rukovanje u toku vožnje.", sv_SE="Begränsad användning under körning.", tr_TR="Sürüş sırasında sınırlı kullanım.", uk_UA="Під час руху керування обмежено.")
